import type { MatrixData, WorkspaceState } from "@core/contracts";

function clampDimension(value: number): number {
  if (!Number.isFinite(value)) {
    return 2;
  }

  return Math.min(6, Math.max(2, Math.round(value)));
}

function normalizeMatrixCell(value: unknown): number {
  return typeof value === "number" && Number.isFinite(value) ? value : 0;
}

export function createDefaultMatrixData(): MatrixData {
  return {
    rows: 2,
    columns: 2,
    values: [
      [1, 0],
      [0, 1]
    ]
  };
}

export function resizeMatrix(matrix: MatrixData, rows: number, columns: number): MatrixData {
  const nextRows = clampDimension(rows);
  const nextColumns = clampDimension(columns);
  const nextValues = Array.from({ length: nextRows }, (_, rowIndex) =>
    Array.from({ length: nextColumns }, (_, columnIndex) => normalizeMatrixCell(matrix.values[rowIndex]?.[columnIndex]))
  );

  return {
    rows: nextRows,
    columns: nextColumns,
    values: nextValues
  };
}

export function updateMatrixCell(
  matrix: MatrixData,
  rowIndex: number,
  columnIndex: number,
  value: number
): MatrixData {
  const next = resizeMatrix(matrix, matrix.rows, matrix.columns);
  next.values[rowIndex]![columnIndex] = Number.isFinite(value) ? value : 0;
  return next;
}

export function createDefaultWorkspaceState(): WorkspaceState {
  return {
    activeTool: "calculate",
    expressionInput: "",
    matrix: {
      left: createDefaultMatrixData(),
      right: createDefaultMatrixData()
    },
    solver: {
      expression: "",
      method: "newton",
      initialGuess: "0",
      bracketLower: "-1",
      bracketUpper: "1"
    },
    numerical: {
      expression: "",
      tool: "differentiate",
      differentiationMethod: "central",
      integrationMethod: "simpson",
      point: "0",
      intervalStart: "0",
      intervalEnd: "1"
    }
  };
}

export function sanitizeWorkspaceState(workspace: WorkspaceState): WorkspaceState {
  const rightMatrix = workspace.matrix.right
    ? resizeMatrix(workspace.matrix.right, workspace.matrix.right.rows, workspace.matrix.right.columns)
    : createDefaultMatrixData();

  return {
    activeTool: workspace.activeTool,
    expressionInput: workspace.expressionInput,
    matrix: {
      left: resizeMatrix(workspace.matrix.left, workspace.matrix.left.rows, workspace.matrix.left.columns),
      right: rightMatrix
    },
    solver: {
      expression: workspace.solver.expression,
      method: workspace.solver.method,
      initialGuess: workspace.solver.initialGuess,
      bracketLower: workspace.solver.bracketLower,
      bracketUpper: workspace.solver.bracketUpper
    },
    numerical: {
      expression: workspace.numerical.expression,
      tool: workspace.numerical.tool,
      differentiationMethod:
        workspace.numerical.differentiationMethod === "five-point" ? "five-point" : "central",
      integrationMethod:
        workspace.numerical.integrationMethod === "trapezoidal" ? "trapezoidal" : "simpson",
      point: workspace.numerical.point,
      intervalStart: workspace.numerical.intervalStart,
      intervalEnd: workspace.numerical.intervalEnd
    }
  };
}

import { useEffect, useState, type Dispatch, type SetStateAction } from "react";
import type {
  CalculatorSettings,
  ResultEnvelope,
  SolverDraft,
  SolverResult
} from "@core/contracts";
import { createDefaultWorkspaceState } from "../../app/workspaceDrafts";
import { createSolverService } from "../../services/solver";
import {
  buildSolverRequest,
  formatMethodLabel,
  formatTerminationReason
} from "./model";
import "./solver.css";

interface SolverWorkbenchProps {
  settings: CalculatorSettings;
  draft: SolverDraft;
  onDraftChange(recipe: (current: SolverDraft) => SolverDraft): void;
  onResultChange: Dispatch<SetStateAction<ResultEnvelope<SolverResult> | null>>;
}

const solverService = createSolverService();
const defaultDraft = createDefaultWorkspaceState().solver;

export function SolverWorkbench({
  settings,
  draft,
  onDraftChange,
  onResultChange
}: SolverWorkbenchProps) {
  const [result, setResult] = useState<ResultEnvelope<SolverResult> | null>(null);

  useEffect(() => {
    onResultChange(result);
  }, [onResultChange, result]);

  useEffect(() => {
    setResult(null);
  }, [
    draft.bracketLower,
    draft.bracketUpper,
    draft.expression,
    draft.initialGuess,
    draft.method,
    settings
  ]);

  function submit() {
    const parsed = buildSolverRequest(draft, settings);
    if (!parsed.ok) {
      setResult({
        ok: false,
        issues: parsed.issues,
        metadata: {
          backend: settings.numeric.backend
        }
      });
      return;
    }

    void Promise.resolve(solverService.solve(parsed.value)).then((nextResult) => setResult(nextResult));
  }

  function resetDraft() {
    onDraftChange(() => defaultDraft);
    setResult(null);
  }

  return (
    <section className="solver-workbench">
      <header className="solver-toolbar">
        <div>
          <p className="eyebrow">Solver mode</p>
          <h3>One-variable root finder</h3>
          <p className="solver-caption">
            Solve equations in x with Newton-Raphson or bisection. Enter either a zero-form expression such
            as `cos(x) - x` or an explicit equation such as `x^2 = 2`.
          </p>
        </div>
        <div className="solver-toolbar-actions">
          <button type="button" className="secondary-button" onClick={resetDraft}>
            Reset draft
          </button>
          <button type="button" className="primary-button" onClick={submit}>
            Solve equation
          </button>
        </div>
      </header>

      <div className="solver-meta-strip">
        <span>Backend: {settings.numeric.backend}</span>
        <span>Tolerance: {settings.numeric.solverTolerance}</span>
        <span>Max iterations: {settings.numeric.maxIterations}</span>
        <span>Display: {settings.numeric.displayMode}</span>
      </div>

      <div className="solver-pane-grid">
        <article className="solver-pane">
          <div className="form-grid">
            <label className="field field-wide">
              <span>Expression or equation</span>
              <textarea
                rows={5}
                value={draft.expression}
                onChange={(event) =>
                  onDraftChange((current) => ({
                    ...current,
                    expression: event.target.value
                  }))
                }
                placeholder="cos(x) - x"
              />
            </label>
            <label className="field">
              <span>Method</span>
              <select
                value={draft.method}
                onChange={(event) =>
                  onDraftChange((current) => ({
                    ...current,
                    method: event.target.value === "bisection" ? "bisection" : "newton"
                  }))
                }
              >
                <option value="newton">Newton-Raphson</option>
                <option value="bisection">Bisection</option>
              </select>
            </label>
            <label className="field">
              <span>Initial guess</span>
              <input
                type="text"
                inputMode="decimal"
                disabled={draft.method !== "newton"}
                value={draft.initialGuess}
                onChange={(event) =>
                  onDraftChange((current) => ({
                    ...current,
                    initialGuess: event.target.value
                  }))
                }
              />
            </label>
            <label className="field">
              <span>Bracket lower</span>
              <input
                type="text"
                inputMode="decimal"
                disabled={draft.method !== "bisection"}
                value={draft.bracketLower}
                onChange={(event) =>
                  onDraftChange((current) => ({
                    ...current,
                    bracketLower: event.target.value
                  }))
                }
              />
            </label>
            <label className="field">
              <span>Bracket upper</span>
              <input
                type="text"
                inputMode="decimal"
                disabled={draft.method !== "bisection"}
                value={draft.bracketUpper}
                onChange={(event) =>
                  onDraftChange((current) => ({
                    ...current,
                    bracketUpper: event.target.value
                  }))
                }
              />
            </label>
          </div>
        </article>

        <article className="solver-pane solver-note-pane">
          <h4>{formatMethodLabel(draft.method)}</h4>
          <p className="solver-caption">
            {draft.method === "newton"
              ? "Newton-Raphson uses the initial guess and a numerical derivative built on the shared expression runtime."
              : "Bisection requires an interval whose endpoints evaluate with opposite signs."}
          </p>
        </article>
      </div>

      <SolverResultPanel result={result} />
    </section>
  );
}

function SolverResultPanel({ result }: { result: ResultEnvelope<SolverResult> | null }) {
  if (!result) {
    return (
      <article className="solver-result-panel">
        <h4>Result</h4>
        <p className="solver-caption">
          Run the solver to inspect the root estimate, residual, termination reason, and iteration history.
        </p>
      </article>
    );
  }

  return (
    <article className="solver-result-panel">
      <header className="solver-pane-header">
        <h4>Result</h4>
        <span className={result.ok ? "status-badge status-ok" : "status-badge status-error"}>
          {result.ok ? "Computed" : "Blocked"}
        </span>
      </header>

      {result.issues.length > 0 ? (
        <div className="issue-stack">
          {result.issues.map((issue) => (
            <div
              key={`${issue.code}-${issue.field ?? "general"}`}
              className={issue.severity === "warning" ? "issue-chip issue-warning" : "issue-chip issue-error"}
            >
              <strong>{issue.code}</strong>
              <span>{issue.message}</span>
            </div>
          ))}
        </div>
      ) : null}

      {result.ok ? (
        <>
          <div className="solver-summary-grid">
            <div>
              <dt>Root</dt>
              <dd>{result.value.formattedRoot}</dd>
            </div>
            <div>
              <dt>Residual</dt>
              <dd>{result.value.formattedResidual}</dd>
            </div>
            <div>
              <dt>Status</dt>
              <dd>{result.value.converged ? "Converged" : "Not converged"}</dd>
            </div>
            <div>
              <dt>Stop reason</dt>
              <dd>{formatTerminationReason(result.value.terminationReason)}</dd>
            </div>
            <div>
              <dt>Iterations</dt>
              <dd>{result.value.iterations}</dd>
            </div>
            <div>
              <dt>Tolerance</dt>
              <dd>{result.value.tolerance}</dd>
            </div>
          </div>

          <div className="solver-history">
            <div className="solver-history-header">
              <strong>Iteration history</strong>
              <span>{result.value.history.length} samples</span>
            </div>
            <div className="solver-history-table" role="table" aria-label="Solver iteration history">
              <div className="solver-history-row solver-history-head" role="row">
                <span>Iter</span>
                <span>Estimate</span>
                <span>Residual</span>
                <span>Step</span>
              </div>
              {result.value.history.map((entry) => (
                <div className="solver-history-row" key={`${entry.iteration}-${entry.estimate}`} role="row">
                  <span>{entry.iteration}</span>
                  <span>{entry.estimate}</span>
                  <span>{entry.residual}</span>
                  <span>{entry.step ?? "n/a"}</span>
                </div>
              ))}
            </div>
          </div>
        </>
      ) : (
        <p className="solver-caption">Fix the flagged input or interval issue and run the solver again.</p>
      )}
    </article>
  );
}

import type {
  CalculatorSettings,
  ComputationIssue,
  DifferentiationMethod,
  IntegrationMethod,
  NumericalDraft,
  NumericalResult,
  ResultEnvelope
} from "@core/contracts";
import "./numerical-tools.css";

interface NumericalToolsWorkspaceProps {
  settings: CalculatorSettings;
  draft: NumericalDraft;
  result: ResultEnvelope<NumericalResult> | null;
  onDraftChange(recipe: (current: NumericalDraft) => NumericalDraft): void;
}

export function NumericalToolsWorkspace({
  settings,
  draft,
  result,
  onDraftChange
}: NumericalToolsWorkspaceProps) {
  const activeTool = draft.tool === "integrate" ? "integrate" : "differentiate";
  const issues = result?.issues ?? fallbackIssues(activeTool);

  return (
    <section className="panel numerical-workspace">
      <header className="panel-header">
        <h2>Numerical Tools</h2>
        <span>live analysis</span>
      </header>

      <div className="numerical-layout">
        <div className="numerical-stack">
          <div className="numerical-meta-strip">
            <span>Backend: {settings.numeric.backend}</span>
            <span>Tolerance: {formatCompact(settings.numeric.solverTolerance)}</span>
            <span>Display: {settings.numeric.displayMode}</span>
            <span>Precision: {settings.numeric.displayPrecision} digits</span>
          </div>

          <div className="form-grid">
            <label className="field field-wide">
              <span>Expression in x</span>
              <textarea
                rows={5}
                value={draft.expression}
                onChange={(event) =>
                  onDraftChange((current) => ({
                    ...current,
                    expression: event.target.value
                  }))
                }
                placeholder="sin(x) * exp(-x)"
              />
            </label>

            <label className="field">
              <span>Tool</span>
              <select
                value={activeTool}
                onChange={(event) =>
                  onDraftChange((current) => ({
                    ...current,
                    tool: event.target.value === "integrate" ? "integrate" : "differentiate"
                  }))
                }
              >
                <option value="differentiate">Differentiate</option>
                <option value="integrate">Integrate</option>
              </select>
            </label>

            {activeTool === "differentiate" ? (
              <>
                <label className="field">
                  <span>Method</span>
                  <select
                    value={draft.differentiationMethod}
                    onChange={(event) =>
                      onDraftChange((current) => ({
                        ...current,
                        differentiationMethod:
                          event.target.value === "five-point" ? "five-point" : "central"
                      }))
                    }
                  >
                    <option value="central">Central difference</option>
                    <option value="five-point">Five-point stencil</option>
                  </select>
                </label>
                <label className="field">
                  <span>Point</span>
                  <input
                    type="text"
                    inputMode="decimal"
                    value={draft.point}
                    onChange={(event) =>
                      onDraftChange((current) => ({
                        ...current,
                        point: event.target.value
                      }))
                    }
                  />
                </label>
              </>
            ) : (
              <>
                <label className="field">
                  <span>Method</span>
                  <select
                    value={draft.integrationMethod}
                    onChange={(event) =>
                      onDraftChange((current) => ({
                        ...current,
                        integrationMethod:
                          event.target.value === "trapezoidal" ? "trapezoidal" : "simpson"
                      }))
                    }
                  >
                    <option value="simpson">Simpson</option>
                    <option value="trapezoidal">Trapezoidal</option>
                  </select>
                </label>
                <label className="field">
                  <span>Interval Start</span>
                  <input
                    type="text"
                    inputMode="decimal"
                    value={draft.intervalStart}
                    onChange={(event) =>
                      onDraftChange((current) => ({
                        ...current,
                        intervalStart: event.target.value
                      }))
                    }
                  />
                </label>
                <label className="field">
                  <span>Interval End</span>
                  <input
                    type="text"
                    inputMode="decimal"
                    value={draft.intervalEnd}
                    onChange={(event) =>
                      onDraftChange((current) => ({
                        ...current,
                        intervalEnd: event.target.value
                      }))
                    }
                  />
                </label>
              </>
            )}
          </div>
        </div>

        <div className="numerical-stack">
          <div className="result-card">
            <p className="result-label">Formatted result</p>
            <output className="result-value">
              {result?.ok ? result.value.formattedValue : draft.expression.trim() ? "Error" : "Ready"}
            </output>
            <p className="result-meta">
              {result?.ok
                ? `Approximation ${formatApproximation(result.value.approximateValue)}`
                : "Results update when the draft, settings, and numerical method change."}
            </p>
          </div>

          <div className="numerical-detail-grid">
            <div className="result-box">
              <span>Method</span>
              <strong>{result?.ok ? labelMethod(result.value.method) : labelPendingMethod(activeTool, draft)}</strong>
            </div>
            <div className="result-box">
              <span>Status</span>
              <strong>{result?.ok ? "ok" : result ? "diagnostic" : "idle"}</strong>
            </div>
            <div className="result-box">
              <span>Error estimate</span>
              <strong>{result?.ok ? formatCompact(result.value.errorEstimate) : "n/a"}</strong>
            </div>
            <div className="result-box">
              <span>Samples</span>
              <strong>{result?.ok ? String(result.value.sampleCount ?? "n/a") : "n/a"}</strong>
            </div>
            <div className="result-box">
              <span>Step size</span>
              <strong>{result?.ok ? formatCompact(result.value.stepSize) : "n/a"}</strong>
            </div>
            <div className="result-box">
              <span>Canonical</span>
              <strong>{result?.ok ? result.value.canonicalExpression : "n/a"}</strong>
            </div>
          </div>

          <div className="issue-list">
            {issues.map((issue) => (
              <div
                className={issue.severity === "error" ? "issue issue-error" : "issue"}
                key={`${issue.code}-${issue.field ?? "general"}`}
              >
                <strong>{issue.code}</strong>
                <span>{issue.message}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

function fallbackIssues(tool: "differentiate" | "integrate"): ComputationIssue[] {
  return [
    {
      code: "numerical.examples",
      message:
        tool === "differentiate"
          ? "Try `sin(x)` at `0`, `x^3 - 2*x` at `2`, or `abs(x)` at `0` to inspect reliability warnings."
          : "Try `x^2` on `[0, 1]`, `sin(x)` on `[0, pi]`, or tighten tolerance with trapezoidal mode to inspect warnings.",
      severity: "warning"
    }
  ];
}

function formatApproximation(value: number | undefined): string {
  if (value === undefined) {
    return "n/a";
  }

  return Number.isFinite(value) ? value.toPrecision(12) : String(value);
}

function formatCompact(value: number | undefined): string {
  if (value === undefined) {
    return "n/a";
  }

  if (!Number.isFinite(value)) {
    return String(value);
  }

  return Number.parseFloat(value.toPrecision(8)).toString();
}

function labelMethod(method: DifferentiationMethod | IntegrationMethod): string {
  switch (method) {
    case "central":
      return "Central difference";
    case "five-point":
      return "Five-point stencil";
    case "trapezoidal":
      return "Trapezoidal";
    case "simpson":
      return "Simpson";
  }
}

function labelPendingMethod(tool: "differentiate" | "integrate", draft: NumericalDraft): string {
  return labelMethod(tool === "integrate" ? draft.integrationMethod : draft.differentiationMethod);
}

