function buildNumericalRequest(
  draft: NumericalDraft,
  settings: CalculatorSettings
): { ok: true; value: NumericalRequest } | { ok: false; issues: ComputationIssue[] } {
  const tool = draft.tool === "integrate" ? "integrate" : "differentiate";

  if (tool === "differentiate") {
    const point = Number(draft.point);
    if (!Number.isFinite(point)) {
      return {
        ok: false,
        issues: [
          {
            code: "numerical.invalid_point",
            message: "Enter a finite point for differentiation.",
            severity: "error",
            field: "point"
          }
        ]
      };
    }

    return {
      ok: true,
      value: {
        tool,
        expression: draft.expression,
        settings,
        point,
        differentiationMethod: draft.differentiationMethod
      }
    };
  }

  const start = Number(draft.intervalStart);
  const end = Number(draft.intervalEnd);
  if (!Number.isFinite(start) || !Number.isFinite(end)) {
    return {
      ok: false,
      issues: [
        {
          code: "numerical.invalid_interval",
          message: "Enter finite interval bounds for integration.",
          severity: "error",
          field: "interval"
        }
      ]
    };
  }

  return {
    ok: true,
    value: {
      tool,
      expression: draft.expression,
      settings,
      interval: [start, end],
      integrationMethod: draft.integrationMethod
    }
  };
}

function failEnvelope<T>(
  settings: CalculatorSettings,
  issues: ComputationIssue[]
): ResultEnvelope<T> {
  return {
    ok: false,
    issues,
    metadata: {
      backend: settings.numeric.backend
    }
  };
}

function labelNumericalMethod(method: NumericalResult["method"]): string {
  switch (method) {
    case "central":
      return "Central difference";
    case "five-point":
      return "Five-point stencil";
    case "trapezoidal":
      return "Trapezoidal";
    case "simpson":
      return "Simpson";
  }
}

/**
 * Shared computation contracts for the calculator. All feature UIs talk only to typed service interfaces defined here. Expression, matrix, solver, and numerical-analysis engines must remain pure modules with no React, persistence, or Tauri imports. Persisted settings and workspace state flow only through versioned schemas. New feature code may depend on settings, numeric backend, and result envelopes, but must not reach into sibling engine internals.
 */

export type MaybePromise<T> = T | Promise<T>;

export type NumericBackend = "float64" | "decimal";
export type AngleMode = "degree" | "radian";
export type DisplayMode = "normal" | "scientific" | "engineering";
export type WorkspaceToolId = "calculate" | "matrix" | "solver" | "numerical";

export interface NumericSettings {
  backend: NumericBackend;
  displayPrecision: number;
  internalPrecision: number;
  solverTolerance: number;
  maxIterations: number;
  angleMode: AngleMode;
  displayMode: DisplayMode;
}

export interface CalculatorSettings {
  numeric: NumericSettings;
  locale: string;
}

export interface ComputationIssue {
  code: string;
  message: string;
  severity: "warning" | "error";
  field?: string;
}

export interface ResultMetadata {
  backend: NumericBackend;
  elapsedMs?: number;
}

export interface SuccessfulResult<T> {
  ok: true;
  value: T;
  issues: ComputationIssue[];
  metadata: ResultMetadata;
}

export interface FailedResult {
  ok: false;
  issues: ComputationIssue[];
  metadata: ResultMetadata;
}

export type ResultEnvelope<T> = SuccessfulResult<T> | FailedResult;

export interface ExpressionRequest {
  expression: string;
  settings: CalculatorSettings;
  variables?: Record<string, number | string>;
}

export interface ExpressionResult {
  canonicalExpression: string;
  formattedValue: string;
  approximateValue: number | null;
}

export interface MatrixData {
  rows: number;
  columns: number;
  values: number[][];
}

export type MatrixOperation =
  | "add"
  | "subtract"
  | "multiply"
  | "transpose"
  | "determinant"
  | "inverse";

export interface MatrixOperationRequest {
  operation: MatrixOperation;
  left: MatrixData;
  right?: MatrixData;
  settings: CalculatorSettings;
}

export interface ConditionDiagnostics {
  pivotStrategy: "none" | "partial";
