import { describe, expect, it } from "vitest";
import type { CalculatorSettings } from "@core/contracts";
import { createDefaultSettingsDocument } from "@persistence/schema";
import { createNumericalToolsService } from "../../src/services/numerical";

function makeSettings(overrides?: Partial<CalculatorSettings["numeric"]>): CalculatorSettings {
  return {
    ...createDefaultSettingsDocument().payload,
    numeric: {
      ...createDefaultSettingsDocument().payload.numeric,
      ...overrides
    }
  };
}

describe("numerical tools service", () => {
  it("differentiates with angle-aware central differences", async () => {
    const service = createNumericalToolsService();
    const result = await service.run({
      tool: "differentiate",
      expression: "sin(x)",
      point: 0,
      differentiationMethod: "central",
      settings: makeSettings({
        angleMode: "degree",
        solverTolerance: 1e-8
      })
    });

    expect(result.ok).toBe(true);
    if (!result.ok) {
      return;
    }

    expect(result.value.method).toBe("central");
    expect(result.value.approximateValue).toBeCloseTo(Math.PI / 180, 6);
  });

  it("integrates smooth functions accurately with Simpson panels", async () => {
    const service = createNumericalToolsService();
    const result = await service.run({
      tool: "integrate",
      expression: "x^2",
      interval: [0, 1],
      integrationMethod: "simpson",
      settings: makeSettings({
        solverTolerance: 1e-10
      })
    });

    expect(result.ok).toBe(true);
    if (!result.ok) {
      return;
    }

    expect(result.value.method).toBe("simpson");
    expect(result.value.approximateValue).toBeCloseTo(1 / 3, 10);
    expect(result.issues).toEqual([]);
  });

  it("surfaces a warning near non-smooth derivative points", async () => {
    const service = createNumericalToolsService();
    const result = await service.run({
      tool: "differentiate",
      expression: "abs(x)",
      point: 0,
      differentiationMethod: "central",
      settings: makeSettings({
        solverTolerance: 1e-10
      })
    });

    expect(result.ok).toBe(true);
    if (!result.ok) {
      return;
    }

    expect(result.issues.map((issue) => issue.code)).toContain("numerical.point_nonsmooth");
  });

  it("warns when trapezoidal refinement exhausts the panel budget", async () => {
    const service = createNumericalToolsService();
    const result = await service.run({
      tool: "integrate",
      expression: "sin(x)",
      interval: [0, Math.PI],
      integrationMethod: "trapezoidal",
      settings: makeSettings({
        solverTolerance: 1e-12,
        maxIterations: 4
      })
    });

    expect(result.ok).toBe(true);
    if (!result.ok) {
      return;
    }

    expect(result.issues.map((issue) => issue.code)).toContain("numerical.integration_not_converged");
  });

  it("fails clearly when the integrand is singular at an endpoint", async () => {
    const service = createNumericalToolsService();
    const result = await service.run({
      tool: "integrate",
      expression: "1 / sqrt(x)",
      interval: [0, 1],
      integrationMethod: "simpson",
      settings: makeSettings()
    });

    expect(result.ok).toBe(false);
    if (result.ok) {
      return;
    }

    expect(result.issues[0]?.code).toBe("math.division_by_zero");
  });
});

import type {
  NumericalRequest,
  NumericalResult,
  NumericalToolsService,
  ResultEnvelope
} from "@core/contracts";
import { runNumericalAnalysis } from "@core/numerical";
import {
  createDecimalRuntime,
  createFloat64Runtime,
  normalizeNumericSettings,
  type NumericRuntime
} from "@core/precision";

export function createNumericalToolsService(): NumericalToolsService {
  return {
    run(request) {
      const startedAt = now();
      const normalizedRequest = {
        ...request,
        settings: {
          ...request.settings,
          numeric: normalizeNumericSettings(request.settings.numeric)
        }
      };

      if (normalizedRequest.settings.numeric.backend === "decimal") {
        return executeWithRuntime(normalizedRequest, createDecimalRuntime(normalizedRequest.settings.numeric), startedAt);
      }

      return executeWithRuntime(normalizedRequest, createFloat64Runtime(normalizedRequest.settings.numeric), startedAt);
    }
  };
}

function executeWithRuntime<TValue>(
  request: NumericalRequest,
  runtime: NumericRuntime<TValue>,
  startedAt: number
): ResultEnvelope<NumericalResult> {
  const outcome = runNumericalAnalysis(request, runtime);

  if (!outcome.ok) {
    return {
      ok: false,
      issues: outcome.issues,
      metadata: {
        backend: runtime.backend,
        elapsedMs: now() - startedAt
      }
    };
  }

  return {
    ok: true,
    value: {
      tool: outcome.value.tool,
      method: outcome.value.method,
      canonicalExpression: outcome.value.canonicalExpression,
      formattedValue: runtime.toDisplayString(
        outcome.value.value,
        request.settings.numeric.displayMode,
        request.settings.numeric.displayPrecision
      ),
      approximateValue: outcome.value.approximateValue,
      sampleCount: outcome.value.sampleCount,
      ...(outcome.value.errorEstimate !== undefined ? { errorEstimate: outcome.value.errorEstimate } : {}),
      ...(outcome.value.stepSize !== undefined ? { stepSize: outcome.value.stepSize } : {})
    },
    issues: outcome.issues,
    metadata: {
      backend: runtime.backend,
      elapsedMs: now() - startedAt
    }
  };
}

function now(): number {
  return globalThis.performance?.now() ?? Date.now();
}

import type { CalculatorSettings, MatrixData, WorkspaceState } from "@core/contracts";
import type { HistoryEntry, HistoryModeMetadata } from "../features/history/model";
import type { MemoryRegister } from "../features/memory/model";
import { createDefaultMemoryRegisters } from "../features/memory/model";
import { createDefaultWorkspaceState, sanitizeWorkspaceState } from "../app/workspaceDrafts";
import { createDefaultCalculatorSettings, sanitizeCalculatorSettings } from "../features/settings/model";

export const SETTINGS_SCHEMA_VERSION = 1 as const;
export const WORKSPACE_SCHEMA_VERSION = 1 as const;
export const HISTORY_SCHEMA_VERSION = 1 as const;
export const MEMORY_SCHEMA_VERSION = 1 as const;

export interface VersionedDocument<TVersion extends number, TPayload> {
  version: TVersion;
  payload: TPayload;
  updatedAt: string;
}

export type PersistedSettingsDocument = VersionedDocument<typeof SETTINGS_SCHEMA_VERSION, CalculatorSettings>;
export type PersistedWorkspaceDocument = VersionedDocument<typeof WORKSPACE_SCHEMA_VERSION, WorkspaceState>;
export type PersistedHistoryDocument = VersionedDocument<typeof HISTORY_SCHEMA_VERSION, { entries: HistoryEntry[] }>;
export type PersistedMemoryDocument = VersionedDocument<typeof MEMORY_SCHEMA_VERSION, { registers: MemoryRegister[] }>;

const DEFAULT_UPDATED_AT = new Date(0).toISOString();

export function createDefaultSettingsDocument(): PersistedSettingsDocument {
  return {
    version: SETTINGS_SCHEMA_VERSION,
    updatedAt: DEFAULT_UPDATED_AT,
    payload: createDefaultCalculatorSettings()
  };
}

export function createDefaultWorkspaceDocument(): PersistedWorkspaceDocument {
  return {
    version: WORKSPACE_SCHEMA_VERSION,
    updatedAt: DEFAULT_UPDATED_AT,
    payload: createDefaultWorkspaceState()
  };
}

export function createDefaultHistoryDocument(): PersistedHistoryDocument {
  return {
    version: HISTORY_SCHEMA_VERSION,
    updatedAt: DEFAULT_UPDATED_AT,
    payload: {
      entries: []
    }
  };
}

export function createDefaultMemoryDocument(): PersistedMemoryDocument {
  return {
    version: MEMORY_SCHEMA_VERSION,
    updatedAt: DEFAULT_UPDATED_AT,
    payload: {
      registers: createDefaultMemoryRegisters()
    }
  };
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function isMatrixData(value: unknown): value is MatrixData {
  if (!isRecord(value)) {
    return false;
  }

  return (
    typeof value.rows === "number" &&
    typeof value.columns === "number" &&
    Array.isArray(value.values) &&
    value.values.every(
      (row) => Array.isArray(row) && row.every((entry) => typeof entry === "number")
    )
  );
}

function isCalculatorSettings(value: unknown): value is CalculatorSettings {
  if (!isRecord(value) || !isRecord(value.numeric)) {
    return false;
  }

  const numeric = value.numeric;

  return (
    (numeric.backend === "float64" || numeric.backend === "decimal") &&
    typeof numeric.displayPrecision === "number" &&
    typeof numeric.internalPrecision === "number" &&
    typeof numeric.solverTolerance === "number" &&
    typeof numeric.maxIterations === "number" &&
    (numeric.angleMode === "degree" || numeric.angleMode === "radian") &&
    (numeric.displayMode === "normal" ||
      numeric.displayMode === "scientific" ||
      numeric.displayMode === "engineering") &&
    typeof value.locale === "string"
  );
}

function isHistoryModeMetadata(value: unknown): value is HistoryModeMetadata {
  return (
    isRecord(value) &&
    (value.backend === "float64" || value.backend === "decimal") &&
    (value.angleMode === "degree" || value.angleMode === "radian") &&
    (value.displayMode === "normal" || value.displayMode === "scientific" || value.displayMode === "engineering") &&
    typeof value.displayPrecision === "number"
  );
}

function isHistoryEntry(value: unknown): value is HistoryEntry {
  return (
    isRecord(value) &&
    typeof value.id === "string" &&
    (value.tool === "calculate" || value.tool === "matrix" || value.tool === "solver" || value.tool === "numerical") &&
    typeof value.title === "string" &&
    typeof value.detail === "string" &&
    typeof value.value === "string" &&
    typeof value.createdAt === "string" &&
    isHistoryModeMetadata(value.mode)
  );
}

function isMemoryRegister(value: unknown): value is MemoryRegister {
  return (
    isRecord(value) &&
    typeof value.id === "string" &&
    typeof value.label === "string" &&
    typeof value.value === "string" &&
    typeof value.detail === "string" &&
    (value.sourceTool === null ||
      value.sourceTool === "calculate" ||
      value.sourceTool === "matrix" ||
      value.sourceTool === "solver" ||
      value.sourceTool === "numerical") &&
    (value.updatedAt === null || typeof value.updatedAt === "string") &&
    (value.mode === null || isHistoryModeMetadata(value.mode))
  );
}

function isWorkspaceState(value: unknown): value is WorkspaceState {
  if (!isRecord(value) || !isRecord(value.matrix) || !isRecord(value.solver) || !isRecord(value.numerical)) {
    return false;
  }

  return (
    (value.activeTool === "calculate" ||
      value.activeTool === "matrix" ||
      value.activeTool === "solver" ||
      value.activeTool === "numerical") &&
    typeof value.expressionInput === "string" &&
    isMatrixData(value.matrix.left) &&
    (!("right" in value.matrix) || value.matrix.right === undefined || isMatrixData(value.matrix.right)) &&
    typeof value.solver.expression === "string" &&
    (value.solver.method === "newton" || value.solver.method === "bisection") &&
    typeof value.solver.initialGuess === "string" &&
    typeof value.solver.bracketLower === "string" &&
    typeof value.solver.bracketUpper === "string" &&
    typeof value.numerical.expression === "string" &&
    (value.numerical.tool === "differentiate" ||
      value.numerical.tool === "integrate" ||
      value.numerical.tool === "sample") &&
    (value.numerical.differentiationMethod === "central" ||
      value.numerical.differentiationMethod === "five-point") &&
    (value.numerical.integrationMethod === "trapezoidal" ||
      value.numerical.integrationMethod === "simpson") &&
    typeof value.numerical.point === "string" &&
    typeof value.numerical.intervalStart === "string" &&
    typeof value.numerical.intervalEnd === "string"
  );
}

export function parsePersistedSettings(value: unknown): PersistedSettingsDocument | null {
  if (!isRecord(value) || value.version !== SETTINGS_SCHEMA_VERSION || !isCalculatorSettings(value.payload)) {
    return null;
  }

  return {
    version: SETTINGS_SCHEMA_VERSION,
    updatedAt: typeof value.updatedAt === "string" ? value.updatedAt : DEFAULT_UPDATED_AT,
    payload: sanitizeCalculatorSettings(value.payload)
  };
}

export function parsePersistedWorkspace(value: unknown): PersistedWorkspaceDocument | null {
  if (!isRecord(value) || value.version !== WORKSPACE_SCHEMA_VERSION || !isWorkspaceState(value.payload)) {
    return null;
  }

  return {
    version: WORKSPACE_SCHEMA_VERSION,
    updatedAt: typeof value.updatedAt === "string" ? value.updatedAt : DEFAULT_UPDATED_AT,
    payload: sanitizeWorkspaceState(value.payload)
  };
}

export function parsePersistedHistory(value: unknown): PersistedHistoryDocument | null {
  if (
    !isRecord(value) ||
    value.version !== HISTORY_SCHEMA_VERSION ||
    !isRecord(value.payload) ||
    !Array.isArray(value.payload.entries) ||
    !value.payload.entries.every((entry) => isHistoryEntry(entry))
  ) {
    return null;
  }

  return {
    version: HISTORY_SCHEMA_VERSION,
    updatedAt: typeof value.updatedAt === "string" ? value.updatedAt : DEFAULT_UPDATED_AT,
    payload: {
      entries: value.payload.entries
    }
  };
}

export function parsePersistedMemory(value: unknown): PersistedMemoryDocument | null {
  if (
    !isRecord(value) ||
    value.version !== MEMORY_SCHEMA_VERSION ||
    !isRecord(value.payload) ||
    !Array.isArray(value.payload.registers) ||
    !value.payload.registers.every((register) => isMemoryRegister(register))
  ) {
    return null;
  }

  return {
    version: MEMORY_SCHEMA_VERSION,
    updatedAt: typeof value.updatedAt === "string" ? value.updatedAt : DEFAULT_UPDATED_AT,
    payload: {
      registers: value.payload.registers
    }
  };
}

import type { CalculatorSettings, ComputationIssue, WorkspaceState, WorkspaceToolId } from "@core/contracts";
import type { HistoryEntry, HistoryModeMetadata } from "../features/history/model";
import type { MemoryRegister } from "../features/memory/model";

export interface WorkspacePresentation {
  tool: WorkspaceToolId;
  title: string;
  detail: string;
  value: string;
  issues: ComputationIssue[];
}

function formatMatrixLabel(rows: number, columns: number): string {
  return `${rows} x ${columns}`;
}

export function buildModeMetadata(settings: CalculatorSettings): HistoryModeMetadata {
  return {
    backend: settings.numeric.backend,
    angleMode: settings.numeric.angleMode,
    displayMode: settings.numeric.displayMode,
    displayPrecision: settings.numeric.displayPrecision
  };
}

export function summarizeWorkspace(workspace: WorkspaceState): WorkspacePresentation {
  switch (workspace.activeTool) {
    case "calculate":
      return {
        tool: "calculate",
        title: "Expression Draft",
        detail: workspace.expressionInput.trim() || "No expression drafted yet.",
        value: workspace.expressionInput.trim() || "Awaiting input",
        issues: workspace.expressionInput.trim()
          ? []
          : [{ code: "empty-expression", message: "Add an expression to capture a useful snapshot.", severity: "warning" }]
      };
    case "matrix":
      return {
        tool: "matrix",
        title: "Matrix Workspace",
        detail: `Left ${formatMatrixLabel(workspace.matrix.left.rows, workspace.matrix.left.columns)} / Right ${formatMatrixLabel(
          workspace.matrix.right?.rows ?? 2,
          workspace.matrix.right?.columns ?? 2
        )}`,
        value: `Ready for persisted matrix drafts`,
        issues: []
      };
    case "solver":
      return {
        tool: "solver",
        title: "Solver Draft",
        detail: workspace.solver.expression.trim() || "No solver expression drafted yet.",
        value: `${workspace.solver.method} | x0=${workspace.solver.initialGuess}`,
        issues: workspace.solver.expression.trim()
          ? []
          : [{ code: "empty-solver-expression", message: "Add a solver expression before storing a snapshot.", severity: "warning" }]
      };
    case "numerical":
      return {
        tool: "numerical",
        title: "Numerical Draft",
        detail: workspace.numerical.expression.trim() || "No numerical expression drafted yet.",
        value: `${workspace.numerical.tool} | [${workspace.numerical.intervalStart}, ${workspace.numerical.intervalEnd}]`,
        issues: workspace.numerical.expression.trim()
          ? []
          : [{ code: "empty-numerical-expression", message: "Add an expression before storing a numerical snapshot.", severity: "warning" }]
      };
  }
}

export function createHistoryEntry(
  workspace: WorkspaceState,
  settings: CalculatorSettings,
  timestamp: string,
  id: string
): HistoryEntry {
  const presentation = summarizeWorkspace(workspace);

  return {
    id,
    tool: presentation.tool,
    title: presentation.title,
    detail: presentation.detail,
    value: presentation.value,
    createdAt: timestamp,
    mode: buildModeMetadata(settings)
  };
}

export function captureRegister(
  register: MemoryRegister,
  workspace: WorkspaceState,
  settings: CalculatorSettings,
  timestamp: string
): MemoryRegister {
  const presentation = summarizeWorkspace(workspace);

  return {
    ...register,
    value: presentation.value,
    detail: presentation.detail,
    sourceTool: presentation.tool,
    updatedAt: timestamp,
    mode: buildModeMetadata(settings)
  };
}

import type {
  CalculatorSettings,
  ComputationIssue,
  ResultEnvelope,
  SolverDraft,
  SolverRequest,
  SolverResult
} from "@core/contracts";

export interface SolverPresentation {
  title: string;
  detail: string;
  value: string;
  issues: ComputationIssue[];
}

export function buildSolverRequest(
  draft: SolverDraft,
  settings: CalculatorSettings
): { ok: true; value: SolverRequest } | { ok: false; issues: ComputationIssue[] } {
  const expression = draft.expression.trim();
  if (!expression) {
    return {
      ok: false,
      issues: [
        {
          code: "solver_expression_required",
          message: "Enter an expression or equation in x before solving.",
          severity: "error",
          field: "expression"
        }
      ]
    };
  }

  if (draft.method === "newton") {
    const initialGuess = parseFiniteNumber(draft.initialGuess, "initialGuess", "Provide a finite initial guess for Newton-Raphson.");
    if (!initialGuess.ok) {
      return {
        ok: false,
        issues: [initialGuess.issue]
      };
    }

    return {
      ok: true,
      value: {
        method: draft.method,
        expression,
        initialGuess: initialGuess.value,
        settings
      }
    };
  }

  const lower = parseFiniteNumber(draft.bracketLower, "bracketLower", "Provide a finite lower bound for bisection.");
  const upper = parseFiniteNumber(draft.bracketUpper, "bracketUpper", "Provide a finite upper bound for bisection.");

  if (!lower.ok || !upper.ok) {
    return {
      ok: false,
      issues: [lower, upper]
        .filter((candidate): candidate is { ok: false; issue: ComputationIssue } => !candidate.ok)
        .map((candidate) => candidate.issue)
    };
  }

  if (lower.value >= upper.value) {
    return {
      ok: false,
      issues: [
        {
          code: "solver_invalid_bracket",
          message: "Lower bound must stay below the upper bound for bisection.",
          severity: "error",
          field: "bracket"
        }
      ]
    };
  }

  return {
    ok: true,
    value: {
      method: draft.method,
      expression,
      bracket: [lower.value, upper.value],
      settings
    }
  };
}

export function summarizeSolver(
  draft: SolverDraft,
  result: ResultEnvelope<SolverResult> | null
): SolverPresentation {
  const expression = draft.expression.trim();

  if (!expression) {
    return {
      title: "Solver Draft",
      detail: "No solver expression drafted yet.",
      value: `${formatMethodLabel(draft.method)} ready`,
      issues: [
        {
          code: "empty-solver-expression",
          message: "Add an expression or equation in x before capturing a solver snapshot.",
          severity: "warning"
        }
      ]
    };
  }

  if (!result) {
    return {
      title: "Solver Draft",
      detail: expression,
      value: `${formatMethodLabel(draft.method)} pending`,
      issues: []
    };
  }

  if (!result.ok) {
    return {
      title: "Solver Blocked",
      detail: expression,
      value: "Input blocked",
      issues: result.issues
    };
  }

  return {
    title: result.value.converged ? "Solver Result" : "Solver Diagnostic",
    detail: `${result.value.canonicalExpression} = 0 | ${formatTerminationReason(result.value.terminationReason)}`,
    value: `x = ${result.value.formattedRoot}`,
    issues: result.issues
  };
}

export function formatMethodLabel(method: SolverDraft["method"]): string {
  return method === "bisection" ? "Bisection" : "Newton-Raphson";
}

export function formatTerminationReason(reason: SolverResult["terminationReason"]): string {
  switch (reason) {
    case "residual_tolerance":
      return "Residual met tolerance";
    case "interval_tolerance":
      return "Interval width met tolerance";
    case "exact_endpoint":
      return "Endpoint already satisfied the equation";
    case "zero_derivative":
      return "Derivative stalled near zero";
    case "max_iterations":
      return "Iteration limit reached";
  }
}

function parseFiniteNumber(
  rawValue: string,
  field: string,
  message: string
): { ok: true; value: number } | { ok: false; issue: ComputationIssue } {
  const normalized = rawValue.trim();
  if (!normalized) {
    return {
      ok: false,
      issue: {
        code: "solver_input_required",
        message,
        severity: "error",
        field
      }
    };
  }

  const numericValue = Number(normalized);
  if (!Number.isFinite(numericValue)) {
    return {
      ok: false,
      issue: {
        code: "solver_invalid_value",
        message: "Solver inputs must parse as finite numbers.",
        severity: "error",
        field
      }
    };
  }

  return {
    ok: true,
    value: numericValue
  };
}

import {
  startTransition,
  useDeferredValue,
  useEffect,
  useMemo,
