                <dt>Workspace Schema</dt>
                <dd>v{WORKSPACE_SCHEMA_VERSION}</dd>
              </div>
              <div>
                <dt>History Schema</dt>
                <dd>v{HISTORY_SCHEMA_VERSION}</dd>
              </div>
              <div>
                <dt>Memory Schema</dt>
