                <div>
                  <dt>Updated</dt>
                  <dd>{formatTimestamp(selectedRegister.updatedAt, settings.locale)}</dd>
                </div>
                <div>
                  <dt>Mode</dt>
                  <dd>
                    {selectedRegister.mode
                      ? `${selectedRegister.mode.angleMode} / ${selectedRegister.mode.displayMode}`
                      : "N/A"}
